using UnityEngine;
public class Script
{
    public static object Main()
    {
        try
        {
            var result = "";
            var assemblies = System.AppDomain.CurrentDomain.GetAssemblies();
            foreach (var asm in assemblies)
            {
                foreach (var type in asm.GetTypes())
                {
                    if (type.Name == "TrafficManager" && !type.IsAbstract)
                    {
                        var instance = type.GetProperty("Instance", System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Static);
                        if (instance != null)
                        {
                            var mgr = instance.GetValue(null);
                            if (mgr != null)
                            {
                                result += "TrafficManager found: " + type.FullName + " Instance=" + mgr + "\n";
                                var isInit = type.GetProperty("IsInitialized");
                                if (isInit != null) result += "IsInitialized=" + isInit.GetValue(mgr) + "\n";
                                var vehicleCount = type.GetProperty("VehicleCount");
                                if (vehicleCount != null) result += "VehicleCount=" + vehicleCount.GetValue(mgr) + "\n";
                            }
                            else result += "TrafficManager Instance is null\n";
                        }
                    }
                }
            }
            if (result == "") result = "TrafficManager not found";
            return result;
        }
        catch (System.Exception ex) { return "Error: " + ex.Message; }
    }
}
